//go:build vectors

package search

import (
	"context"
	"fmt"
	"log/slog"
	"time"

	"github.com/a<HOME>/agentic-rag-mcp/internal/config"
	"github.com/a<HOME>/agentic-rag-mcp/internal/embedder"

	"github.com/<HOME>/bleve/v2"
	bleveSearch "github.com/<HOME>/bleve/v2/search"
)

// Searcher provides hybrid search and section retrieval.
type Searcher struct {
	index    bleve.Index
	embedder embedder.Embedder
	cfg      config.SearchConfig
}

// NewSearcher creates a searcher backed by a bleve index.
func NewSearcher(index bleve.Index, emb embedder.Embedder, cfg config.SearchConfig) *Searcher {
	return &Searcher{
		index:    index,
		embedder: emb,
		cfg:      cfg,
	}
}

// Search performs hybrid BM25+KNN search with RRF fusion.
func (s *Searcher) Search(ctx context.Context, query, scope, kind string, tags []string, limit int) (SearchResponse, error) {
	start := time.Now()

	docCount, _ := s.index.DocCount()
	if docCount == 0 {
		return SearchResponse{
			Results:      []SearchResult{},
			TotalMatches: 0,
			SearchTimeMs: 0,
			IndexState:   "empty",
		}, nil
	}

	if limit <= 0 {
		limit = s.cfg.DefaultLimit
	}
	if limit > s.cfg.MaxLimit {
		limit = s.cfg.MaxLimit
	}

	// Build BM25 query
	bm25Query := bleve.NewMatchQuery(query)
	bm25Query.SetField("content")
	bm25Query.Analyzer = "standard"

	// Also search in title
	titleQuery := bleve.NewMatchQuery(query)
	titleQuery.SetField("title")
	titleQuery.Analyzer = "standard"

	// Combine BM25 queries
	textQuery := bleve.NewDisjunctionQuery(bm25Query, titleQuery)

	// Build filters
	var filterQueries []bleve.Query

	if scope != "" && scope != "all" {
		scopeQuery := bleve.NewTermQuery(scope)
		scopeQuery.SetField("scope")
		filterQueries = append(filterQueries, scopeQuery)
	}

	if kind != "" {
		kindQuery := bleve.NewTermQuery(kind)
		kindQuery.SetField("kind")
		filterQueries = append(filterQueries, kindQuery)
	}

	for _, tag := range tags {
		tagQuery := bleve.NewTermQuery(tag)
		tagQuery.SetField("tags")
		filterQueries = append(filterQueries, tagQuery)
	}

	// Combine text query with filters
	var finalQuery bleve.Query
	if len(filterQueries) > 0 {
		allQueries := append([]bleve.Query{textQuery}, filterQueries...)
		finalQuery = bleve.NewConjunctionQuery(allQueries...)
	} else {
		finalQuery = textQuery
	}

	// Execute BM25 search
	bm25Req := bleve.NewSearchRequest(finalQuery)
	bm25Req.Size = limit * 3
	bm25Req.Fields = []string{
		"qualifiedId", "documentSlug", "sectionId", "title",
		"content", "scope", "kind", "tags", "position",
	}

	bm25Results, err := s.index.Search(bm25Req)
	if err != nil {
		return SearchResponse{}, fmt.Errorf("BM25 search: %w", err)
	}

	// Try KNN search
	var knnResults *bleve.SearchResult
	knnAvailable := false

	if s.embedder != nil {
		queryVec, err := s.embedder.Embed(ctx, query, embedder.PurposeQuery)
		if err != nil {
			slog.Warn("embedding failed, falling back to BM25-only", "error", err)
		} else {
			knnReq := bleve.NewSearchRequest(bleve.NewMatchAllQuery())
			knnReq.AddKNN("_vector", queryVec, int64(limit*3), 0)
			knnReq.Size = limit * 3
			knnReq.Fields = bm25Req.Fields

			// Apply filters to KNN query too
			if len(filterQueries) > 0 {
				filterQ := bleve.NewConjunctionQuery(filterQueries...)
				knnReq = bleve.NewSearchRequest(filterQ)
				knnReq.AddKNN("_vector", queryVec, int64(limit*3), 0)
				knnReq.Size = limit * 3
				knnReq.Fields = bm25Req.Fields
			}

			knnResults, err = s.index.Search(knnReq)
			if err != nil {
				slog.Warn("KNN search failed, using BM25 only", "error", err)
			} else {
				knnAvailable = true
			}
		}
	}

	// RRF fusion or BM25-only
	var hits []*bleveSearch.DocumentMatch
	totalMatches := int(bm25Results.Total)

	if knnAvailable && knnResults != nil {
		hits = rrfFuse(bm25Results.Hits, knnResults.Hits, s.cfg.BM25Weight, s.cfg.KNNWeight, s.cfg.RRFK)
		if int(knnResults.Total) > totalMatches {
			totalMatches = int(knnResults.Total)
		}
	} else {
		hits = bm25Results.Hits
	}

	// Cap results
	if len(hits) > limit {
		hits = hits[:limit]
	}

	// Format results
	results := make([]SearchResult, 0, len(hits))
	for _, hit := range hits {
		results = append(results, hitToSearchResult(hit))
	}

	elapsed := time.Since(start)
	return SearchResponse{
		Results:      results,
		TotalMatches: totalMatches,
		SearchTimeMs: elapsed.Milliseconds(),
		IndexState:   "ready",
		BM25Only:     !knnAvailable,
	}, nil
}

// rrfFuse performs Reciprocal Rank Fusion on two result lists.
func rrfFuse(bm25Hits, knnHits []*bleveSearch.DocumentMatch, bm25Weight, knnWeight float64, k int) []*bleveSearch.DocumentMatch {
	type scored struct {
		hit   *bleveSearch.DocumentMatch
		score float64
	}

	scores := make(map[string]*scored)

	for rank, hit := range bm25Hits {
		s := bm25Weight * (1.0 / float64(k+rank+1))
		if existing, ok := scores[hit.ID]; ok {
			existing.score += s
		} else {
			scores[hit.ID] = &scored{hit: hit, score: s}
		}
	}

	for rank, hit := range knnHits {
		s := knnWeight * (1.0 / float64(k+rank+1))
		if existing, ok := scores[hit.ID]; ok {
			existing.score += s
		} else {
			scores[hit.ID] = &scored{hit: hit, score: s}
		}
	}

	result := make([]*bleveSearch.DocumentMatch, 0, len(scores))
	for _, s := range scores {
		s.hit.Score = s.score
		result = append(result, s.hit)
	}

	for i := 1; i < len(result); i++ {
		for j := i; j > 0 && result[j].Score > result[j-1].Score; j-- {
			result[j], result[j-1] = result[j-1], result[j]
		}
	}

	return result
}

func hitToSearchResult(hit *bleveSearch.DocumentMatch) SearchResult {
	content := getString(hit.Fields, "content")
	return SearchResult{
		QualifiedID:  getString(hit.Fields, "qualifiedId"),
		DocumentSlug: getString(hit.Fields, "documentSlug"),
		SectionID:    getString(hit.Fields, "sectionId"),
		Title:        getString(hit.Fields, "title"),
		Score:        hit.Score,
		Snippet:      GenerateSnippet(content, 500),
		Scope:        getString(hit.Fields, "scope"),
		Kind:         getString(hit.Fields, "kind"),
		Tags:         getStringSlice(hit.Fields, "tags"),
	}
}

func getString(fields map[string]interface{}, key string) string {
	if v, ok := fields[key]; ok {
		if s, ok := v.(string); ok {
			return s
		}
	}
	return ""
}

func getStringSlice(fields map[string]interface{}, key string) []string {
	if v, ok := fields[key]; ok {
		switch t := v.(type) {
		case []interface{}:
			result := make([]string, 0, len(t))
			for _, item := range t {
				if s, ok := item.(string); ok {
					result = append(result, s)
				}
			}
			return result
		case []string:
			return t
		case string:
			return []string{t}
		}
	}
	return []string{}
}

func getInt(fields map[string]interface{}, key string) int {
	if v, ok := fields[key]; ok {
		switch t := v.(type) {
		case float64:
			return int(t)
		case int:
			return t
		}
	}
	return 0
}
